        func=mdp.randomize_rigid_body_material,
        mode='startup',
        params={'static_friction_range': (0.4, 1.0), 'dynamic_friction_range': (0.4, 1.0), 'restitution_range': (0.0, 0.2), 'asset_cfg': 'robot'}
